import{_ as i,c as o,o as r,ae as t}from"./chunks/framework.CDjunVez.js";const u=JSON.parse('{"title":"File Manager","description":"","frontmatter":{},"headers":[],"relativePath":"features/filemanager.md","filePath":"features/filemanager.md"}'),a={name:"features/filemanager.md"};function s(n,e,l,d,c,g){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="file-manager" tabindex="-1">File Manager <a class="header-anchor" href="#file-manager" aria-label="Permalink to &quot;File Manager&quot;">​</a></h1><p>KiwiPanel includes a <strong>full-featured, web-based file manager</strong> for every website, as well as a <strong>rescue file manager</strong> with root access for emergency recovery. Browse, edit, upload, download, compress, and manage files directly from the browser — no FTP client or SSH needed.</p><h2 id="browse-navigate" tabindex="-1">Browse &amp; Navigate <a class="header-anchor" href="#browse-navigate" aria-label="Permalink to &quot;Browse &amp; Navigate&quot;">​</a></h2><ul><li>List files and directories with <strong>column sorting</strong> by name, size, or modified date</li><li><strong>Address bar</strong> with manual path entry and auto-complete</li><li><strong>Pagination</strong> with configurable page size (25, 50, 100, 250, or 500 items)</li><li>Directories listed first, sort and page size preferences remembered across sessions</li><li><strong>File type icons</strong> for images, code, documents, archives, and configs</li><li><strong>Keyboard shortcuts</strong> for quick navigation</li></ul><h2 id="file-operations" tabindex="-1">File Operations <a class="header-anchor" href="#file-operations" aria-label="Permalink to &quot;File Operations&quot;">​</a></h2><ul><li><strong>Create</strong> new files and folders</li><li><strong>Inline rename</strong> — double-click a filename, press Enter to save, Escape to cancel</li><li><strong>Copy and move</strong> files between directories — single or bulk</li><li><strong>Delete</strong> with confirmation — single or bulk</li><li><strong>Drag-and-drop</strong> to move files within the file list</li><li><strong>Right-click context menu</strong> for quick access to all actions</li></ul><h2 id="code-editor" tabindex="-1">Code Editor <a class="header-anchor" href="#code-editor" aria-label="Permalink to &quot;Code Editor&quot;">​</a></h2><p>A built-in code editor powered by Ace Editor:</p><ul><li><strong>Multi-tab editing</strong> — open multiple files simultaneously, each with its own session</li><li><strong>Tab bar</strong> — switch between open files, dirty indicator dot for unsaved changes, close with click or middle-click</li><li><strong>File tree sidebar</strong> — collapsible and resizable tree view of the project directory <ul><li>Auto-expands to the currently active file</li><li>Lazy-loads subdirectories on expand</li><li>Toggle with the sidebar button or <code>Ctrl+B</code> / <code>Cmd+B</code></li><li>Resize by dragging the handle; width and collapsed state remembered across sessions</li></ul></li><li><strong>Tree context menu</strong> — right-click files or folders for New File, New Folder, Rename, and Delete</li><li><strong>Inline file/folder creation</strong> — create new files or folders directly from the tree header or context menu</li><li><strong>30+ language modes</strong> — PHP, JavaScript, Python, Go, Rust, Vue, Svelte, Nginx configs, and more</li><li><strong>Toolbar</strong> — language selector, tab size (2sp / 4sp / hard tab), word wrap toggle, font size controls</li><li><strong>Save with <code>Ctrl+S</code> / <code>Cmd+S</code></strong> — with unsaved changes tracking and discard confirmation</li><li><strong>Close tab with <code>Ctrl+W</code> / <code>Cmd+W</code></strong></li><li><strong>Find &amp; Replace</strong> — <code>Ctrl+F</code> / <code>Ctrl+H</code></li><li><strong>Code folding</strong> — collapse blocks for easier navigation</li><li><strong>Preferences remembered</strong> — font size, wrap mode, and tab size saved between sessions</li></ul><h2 id="upload" tabindex="-1">Upload <a class="header-anchor" href="#upload" aria-label="Permalink to &quot;Upload&quot;">​</a></h2><ul><li><strong>Standard upload</strong> for small files</li><li><strong>Resumable chunked upload</strong> for large files — survives network interruptions</li></ul><h2 id="download-preview" tabindex="-1">Download &amp; Preview <a class="header-anchor" href="#download-preview" aria-label="Permalink to &quot;Download &amp; Preview&quot;">​</a></h2><ul><li><strong>Direct download</strong> with support for resuming interrupted downloads</li><li><strong>Image preview</strong> — thumbnails and full-size viewing</li><li><strong>Video and audio streaming</strong> — play media files directly in the browser</li><li><strong>Text preview</strong> — quick view for text-based files</li><li><strong>Archive preview</strong> — peek inside archives without extracting</li></ul><h2 id="compression-extraction" tabindex="-1">Compression &amp; Extraction <a class="header-anchor" href="#compression-extraction" aria-label="Permalink to &quot;Compression &amp; Extraction&quot;">​</a></h2><ul><li><strong>Compress</strong> files and folders into <code>.zip</code>, <code>.tar.gz</code>, or <code>.tar.bz2</code></li><li><strong>Extract</strong> archives including <code>.zip</code>, <code>.tar.gz</code>, <code>.tar.bz2</code>, <code>.7z</code>, and <code>.rar</code></li><li><strong>Bulk compress</strong> — select multiple items and compress in one action</li></ul><h2 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h2><ul><li><strong>Recursive search</strong> across the entire website directory</li><li>Results displayed in a dedicated pane</li></ul><h2 id="download-remote-file" tabindex="-1">Download Remote File <a class="header-anchor" href="#download-remote-file" aria-label="Permalink to &quot;Download Remote File&quot;">​</a></h2><p>Download a file from a URL directly into the website&#39;s directory — like running <code>wget</code> from the browser:</p><ul><li><strong>Real-time progress</strong> with percentage, download speed, and estimated time</li><li><strong>Smart filename detection</strong> from URL or server headers</li><li>Supports HTTP and HTTPS, files up to <strong>10 GB</strong></li></ul><h2 id="trash-recovery" tabindex="-1">Trash &amp; Recovery <a class="header-anchor" href="#trash-recovery" aria-label="Permalink to &quot;Trash &amp; Recovery&quot;">​</a></h2><p>Deleted files go to a trash bin instead of being permanently removed:</p><ul><li><strong>Browse</strong> trashed items</li><li><strong>Restore</strong> files to their original location</li><li><strong>Permanently delete</strong> individual items or empty the entire trash</li></ul><h2 id="permissions-ownership" tabindex="-1">Permissions &amp; Ownership <a class="header-anchor" href="#permissions-ownership" aria-label="Permalink to &quot;Permissions &amp; Ownership&quot;">​</a></h2><ul><li><strong>Permissions dialog</strong> — set read/write/execute with checkboxes, octal preview, and recursive toggle</li><li><strong>Change owner</strong> (admin only) — change file owner and group, single or bulk</li></ul><h2 id="file-properties" tabindex="-1">File Properties <a class="header-anchor" href="#file-properties" aria-label="Permalink to &quot;File Properties&quot;">​</a></h2><ul><li>Right-click any file and select <strong>Properties</strong> to view detailed information including size, permissions, timestamps, and checksums (MD5, SHA256)</li><li><strong>Recursive folder size</strong> calculation on demand</li></ul><h2 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">​</a></h2><p>All actions provide feedback through <strong>toast notifications</strong> — non-intrusive messages that appear briefly without interrupting your workflow.</p><h2 id="rescue-file-manager" tabindex="-1">Rescue File Manager <a class="header-anchor" href="#rescue-file-manager" aria-label="Permalink to &quot;Rescue File Manager&quot;">​</a></h2><p>A separate file manager available at <code>/rescue/files</code> with <strong>unrestricted root access</strong> to the entire filesystem. Intended for emergency recovery and debugging:</p><ul><li><strong>Token authentication</strong> — requires a rescue token generated at install (rotate via <code>kiwipanel terminal rotate</code>)</li><li><strong>Full feature parity</strong> with the website file manager — multi-tab editor, file tree sidebar, context menu, upload, download, compression, search, trash, and permissions</li><li>Accessible from the <strong>Quick Actions</strong> section on the dashboard</li></ul>',32)])])}const m=i(a,[["render",s]]);export{u as __pageData,m as default};
